/** Ya.Spelunky()[25], verbatim. Index = CoralKidUpgBonus's `b` (level lives at OLA[427+b]). */
export const CORAL_KID = [
  { desc: "Lets_you_click_the_volcano,_linking_the_divinity_of_your_choice_to_ALL_players!_Also,_+{%_Divinity_EXP_gain_for_all!" },
  { desc: "The_Max_Level_of_the_''Blessing''_upgrade_for_each_@_Divinity_is_+{_levels_higher!" },
  { desc: "God_Rank_now_also_gives_}x_Class_EXP_to_all_players!_@_Total_Bonus:$x_Class_EXP" },
  { desc: "Divinity_Skill_Lv_boosts_Minor_Link_Bonuses_a_bit_more!_@_(Your_Divinity_LV_of_$_boosts_Minor_Link_Bonuses_by_^x)" },
  { desc: "Boosts_Divinity_PTS_gain_by_+{%_per_Coral_Reef_upgrade!_Total_Bonus:+$%_Divinity_PTS" },
  { desc: "You_now_generate_{%_more_Daily_Coral_for_the_Coral_Reef_back_in_W7_town!" },
];

/** CoralKidUpgBonus(b, level) — level = OLA[427+b] (account-options array, NOT Spelunk[]).
 *  Fully resolved, no unread inputs. */
export function coralKidUpgBonus(b, level) {
  if (!CORAL_KID[b]) throw new Error(`CoralKidUpgBonus(${b}): no CORAL_KID row`);
  const lvl = Number(level ?? 0);
  if (b === 0) return 10 * lvl;
  if (b === 1) return Math.round(2 * lvl);
  if (b === 2) return 20 * (lvl / (25 + lvl));
  if (b === 3) return Math.round(lvl);
  if (b === 4) return Math.round(2 * lvl);
  return 100 * (lvl / (40 + lvl));   // b >= 5
}

/** CoralKidUpgCost(b, level). */
export function coralKidUpgCost(b, level) {
  const lvl = Number(level ?? 0);
  const growth = b === 1 ? 1.25 : 1.10;
  return 1e7 * Math.pow(6, b) * Math.pow(growth, lvl);
}

/** Ya.CoralReef(), verbatim. Only the gameplay columns [0..3]; [4..12] are UI pixel coords,
 *  intentionally omitted (see header). Index = the Coral Reef BUILDING id (Spelunk[13][id]). */
export const CORAL_REEF_BUILDINGS = [
  { desc: "Every_day_you_play,_your_Grind_Time_bubble_gets_+{_LVs", maxLv: 15, costBase: 10, costGrowth: 1.25 },
  { desc: "Orange...",                                              maxLv: 1,  costBase: 10, costGrowth: 1.5 },
  { desc: "Adds_a_new_bonus_to_your_Tome's_Epilogue_in_World_4,_which_goes_up_with_your_Tome_Score!", maxLv: 10, costBase: 15, costGrowth: 1.75 },
  { desc: "Adds_a_new_mini_'Ninja_Knowledge'_upgrade,_level_it_up_with_your_Jade!", maxLv: 12, costBase: 10, costGrowth: 1.65 },
  { desc: "The_Gallery_gives_+{%_higher_bonuses,_@_and_has_+}_more_slots_for_Trophies", maxLv: 10, costBase: 40, costGrowth: 1.6 },
  { desc: "Blue...",                                                maxLv: 1,  costBase: 10, costGrowth: 1.5 },
];

/** ReefCost(b, level) = CORAL_REEF_BUILDINGS[b].costBase * costGrowth^level. */
export function reefCost(b, level) {
  const row = CORAL_REEF_BUILDINGS[b];
  if (!row) throw new Error(`ReefCost(${b}): no CORAL_REEF_BUILDINGS row`);
  return row.costBase * Math.pow(row.costGrowth, Number(level ?? 0));
}

/** Ya.Spelunky()[22]/[23]/[24], verbatim. Index = DancingCoralBonus's `b` (0..8). */
export const DANCING_CORAL = [
  { costBase: 20,     desc: "+{%_Daily_Reef_Coral",           coeff: 2 },
  { costBase: 100,    desc: "+{%_Spelunking_POW",             coeff: 5 },
  { costBase: 250,    desc: "+{%_Spelunking_Amber_gain",      coeff: 3 },
  { costBase: 1000,   desc: "}x_Class_EXP_gain",               coeff: 4 },
  { costBase: 3000,   desc: "+{%_Research_EXP",                coeff: 3 },
  { costBase: 10000,  desc: "+{%_who_knows",                   coeff: 1 },   // unimplemented ("who knows")
  { costBase: 25000,  desc: "+{%_who_knows",                   coeff: 1 },
  { costBase: 100000, desc: "+{%_who_knows",                   coeff: 1 },
  { costBase: 500000, desc: "+{%_who_knows",                   coeff: 1 },
];

/** DancingCoralBonus(b, 999) = raw per-level coeff (no Atom scaling). */
export const dancingCoralBonusRaw = (b) => {
  if (!DANCING_CORAL[b]) throw new Error(`DancingCoralBonus(${b}): no DANCING_CORAL row`);
  return DANCING_CORAL[b].coeff;
};
/** DancingCoralBonus(b, 0) = raw * max(0, towerInfo18Plus - 200). Caller supplies
 *  TowerInfo[18+b] (Atom Collider save key; see atoms.mjs / gamedata-w3-refinery.mjs — this file
 *  does not own that selector). */
export const dancingCoralBonus = (b, towerInfo18PlusB) =>
  dancingCoralBonusRaw(b) * Math.max(0, Number(towerInfo18PlusB ?? 0) - 200);

/** DancingCoralCOST(b, level) — level = the account's Spelunk[4][7] "Grind Time" indicator
 *  (shared discount input across the row; caller supplies it — this file does not own Spelunk
 *  selectors). */
export function dancingCoralCost(b, spelunk4_7) {
  const row = DANCING_CORAL[b];
  if (!row) throw new Error(`DancingCoralCOST(${b}): no DANCING_CORAL row`);
  const x = Number(spelunk4_7 ?? 0);
  const discount = 1 + (10 * x + Math.pow(1.05, x)) / 100;
  return row.costBase / discount;
}
